window.SRVPLUS = window.SRVPLUS || {}; SRVPLUS.questions = SRVPLUS.questions || [];
SRVPLUS.questions.push(
  { id:"D4-001", domain:4, obj:"4.1", diff:"easy", q:"A technician begins troubleshooting a downed file server. Per the CompTIA six-step methodology, what is the FIRST step she should perform?", options:["Establish a theory of probable cause","Identify the problem","Test the theory to determine the cause","Establish a plan of action"], answer:1, explain:"<strong>Identify the problem,</strong> gathering information, questioning users, and identifying changes is always step one of the CompTIA troubleshooting methodology.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Establish a theory of probable cause</b>: This is step two and cannot happen until the problem has first been identified and information gathered.</span><span class='qd'><b>Test the theory to determine the cause</b>: Testing a theory is step three; you must form a theory before you can test it.</span><span class='qd'><b>Establish a plan of action</b>: Planning a resolution is step four, performed only after a confirmed cause.</span>" },
  { id:"D4-002", domain:4, obj:"4.1", diff:"easy", q:"After confirming a probable cause for a service outage, which methodology step comes immediately next?", options:["Establish a plan of action to resolve the problem","Verify full system functionality","Document findings","Question the user"], answer:2, explain:"<strong>Establish a plan of action to resolve the problem</strong> is the step that follows confirming the theory of the cause; the plan precedes implementing the solution.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Document findings</b>: Documentation is the final step, done after the fix is verified.</span><span class='qd'><b>Verify full system functionality</b>: Verification occurs after the solution is implemented, not immediately after confirming the cause.</span><span class='qd'><b>Question the user</b>: Questioning users is part of identifying the problem, the very first step.</span>" },
  { id:"D4-003", domain:4, obj:"4.1", diff:"medium", q:"A junior admin's theory about a failed NIC turns out to be wrong after testing. According to the methodology, what should he do next?", options:["Escalate to a vendor immediately","Re-establish a new theory or escalate","Reboot the server and hope it resolves","Document that the server is unfixable"], answer:2, explain:"<strong>Re-establish a new theory or escalate</strong> is correct; when a theory is disproven, you form a new theory of probable cause or escalate if needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reboot the server and hope it resolves</b>: Random reboots are not part of the methodology and skip forming a valid theory.</span><span class='qd'><b>Escalate to a vendor immediately</b>: Escalation is an option but you first attempt a new theory; jumping to a vendor is premature.</span><span class='qd'><b>Document that the server is unfixable</b>: Documentation of a fix happens at the end; declaring it unfixable abandons the process incorrectly.</span>" },
  { id:"D4-004", domain:4, obj:"4.1", diff:"medium", q:"While identifying a problem, a technician learns a driver was updated last night. Why is asking about recent changes valuable?", options:["Changes often correlate directly with new problems","It satisfies a compliance checkbox only","Drivers never cause server faults","Recent changes are rarely related to issues"], answer:3, explain:"<strong>Changes often correlate directly with new problems</strong> because a newly introduced change (like a driver update) is a leading suspect when symptoms appear right afterward.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recent changes are rarely related to issues</b>: The opposite is true; recent changes are among the most common root causes.</span><span class='qd'><b>It satisfies a compliance checkbox only</b>: Identifying changes is diagnostic, not merely a paperwork formality.</span><span class='qd'><b>Drivers never cause server faults</b>: Incompatible or unstable drivers are a documented cause of slow performance and failures.</span>" },
  { id:"D4-005", domain:4, obj:"4.1", diff:"hard", q:"A change to fix a server requires modifying a production database schema. Best practice before implementing the plan of action is to:", options:["Consult change management and back up first","Skip change management to save time","Implement immediately during peak hours","Delete old backups to free space"], answer:1, explain:"<strong>Consult change management and back up first</strong> because schema changes may be subject to change management and a backup protects against an unsuccessful change.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Skip change management to save time</b>: Bypassing change management on production introduces unmanaged risk.</span><span class='qd'><b>Implement immediately during peak hours</b>: Peak-hour changes maximize user impact and are poor practice.</span><span class='qd'><b>Delete old backups to free space</b>: Removing backups removes your recovery safety net right when you need it most.</span>" },
  { id:"D4-006", domain:4, obj:"4.1", diff:"easy", q:"After fixing a printing service, the technician confirms users can print and implements preventive measures. Which step does verifying functionality and preventing recurrence represent?", options:["Step 3","Step 5","Step 2","Step 1"], answer:2, explain:"<strong>Step 5</strong> verify full system functionality and, if applicable, implement preventive measures, is the fifth step of the methodology.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Step 2</b>: Step 2 is establishing a theory of probable cause.</span><span class='qd'><b>Step 3</b>: Step 3 is testing the theory to determine cause.</span><span class='qd'><b>Step 1</b>: Step 1 is identifying the problem.</span>" },
  { id:"D4-007", domain:4, obj:"4.1", diff:"medium", q:"Why should a technician document findings, actions, and outcomes as the final methodology step?", options:["To build a knowledge base for future incidents","To assign blame to a user","Because logs are automatically deleted","To avoid talking to coworkers"], answer:1, explain:"<strong>To build a knowledge base for future incidents</strong> documentation captures lessons learned so the same issue can be resolved faster next time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To assign blame to a user</b>: Documentation records facts and resolution, not blame.</span><span class='qd'><b>Because logs are automatically deleted</b>: Documentation is independent of log retention behavior.</span><span class='qd'><b>To avoid talking to coworkers</b>: Good documentation aids collaboration; it does not replace communication.</span>" },
  { id:"D4-008", domain:4, obj:"4.1", diff:"medium", q:"A server problem might be at the hardware, OS, or application layer. Why is determining the correct layer an important early step?", options:["It changes who is responsible and how you troubleshoot","All layers are fixed the same way","Only the network layer ever matters","Layers are irrelevant to methodology"], answer:0, explain:"<strong>It changes who is responsible and how you troubleshoot</strong> because methodology and even responsibility vary depending on which layer the problem resides in.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>All layers are fixed the same way</b>: Different layers require different tools and approaches.</span><span class='qd'><b>Only the network layer ever matters</b>: Hardware, OS, and application layers each produce distinct issues.</span><span class='qd'><b>Layers are irrelevant to methodology</b>: Identifying the affected layer directly shapes the troubleshooting path.</span>" },
  { id:"D4-009", domain:4, obj:"4.1", diff:"hard", q:"A technician suspects a hardware fault is surfacing as OS file corruption. A good first action to confirm or rule out hardware is to:", options:["Reinstall the application","Check vendor HCL and run hardware diagnostics","Reset the user's password","Clear the browser cache"], answer:0, explain:"<strong>Check vendor HCL and run hardware diagnostics</strong> verifying the component is on the OS hardware compatibility list and testing hardware helps confirm or rule out a hardware root cause.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reinstall the application</b>: Reinstalling software does nothing to confirm a suspected hardware fault.</span><span class='qd'><b>Reset the user's password</b>: A password reset addresses logon issues, not hardware corruption.</span><span class='qd'><b>Clear the browser cache</b>: Cache clearing is unrelated to server hardware diagnostics.</span>" },
  { id:"D4-010", domain:4, obj:"4.1", diff:"easy", q:"A user reports an issue that turns out to be how they were using the application. The technician should remember that some tickets are caused by:", options:["User error","Cosmic radiation only","Faulty methodology steps","The change management board"], answer:1, explain:"<strong>User error</strong> some issues initially diagnosed as OS or application faults are actually user error, so verifying correct user interaction is part of troubleshooting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cosmic radiation only</b>: While rare bit-flips exist, the documented common cause here is user error.</span><span class='qd'><b>Faulty methodology steps</b>: Methodology is a process, not a root cause of the user's reported issue.</span><span class='qd'><b>The change management board</b>: Change management governs changes; it is not the cause of a usage mistake.</span>" },
  { id:"D4-011", domain:4, obj:"4.1", diff:"medium", q:"One of the best ways to diagnose suspected user error is to:", options:["Ask the user to demonstrate what they were doing","Assume the user is lying","Immediately reimage the workstation","Disable the user's account"], answer:1, explain:"<strong>Ask the user to demonstrate what they were doing</strong> watching the user reproduce the steps is one of the best ways to identify user error.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume the user is lying</b>: Assuming bad faith is unprofessional and unhelpful for diagnosis.</span><span class='qd'><b>Immediately reimage the workstation</b>: Reimaging is drastic and skips identifying the actual cause.</span><span class='qd'><b>Disable the user's account</b>: Disabling the account prevents diagnosis and disrupts the user.</span>" },
  { id:"D4-012", domain:4, obj:"4.1", diff:"hard", q:"During the plan-of-action phase, a fix could affect a clustered service. The technician should account for:", options:["Resource and downtime implications across nodes","Only the color of the rack","Nothing; clusters self-heal","User lunch schedules"], answer:2, explain:"<strong>Resource and downtime implications across nodes</strong> planning must consider how the change affects cluster resources and availability so the whole cluster is not brought down at once.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Nothing; clusters self-heal</b>: Clusters require careful, node-by-node handling; they do not absolve planning.</span><span class='qd'><b>Only the color of the rack</b>: Cosmetic details are irrelevant to a service-impacting plan.</span><span class='qd'><b>User lunch schedules</b>: While timing matters, the key technical concern is resource and downtime impact.</span>" },
  { id:"D4-013", domain:4, obj:"4.1", diff:"medium", q:"A widespread outage affects many systems. Establishing the scope of the problem during identification helps the technician:", options:["Ignore the affected users","Determine whether it is isolated or systemic","Skip forming a theory","Avoid documentation"], answer:1, explain:"<strong>Determine whether it is isolated or systemic</strong> knowing the scope (one host vs many) guides whether the cause is local or an infrastructure-wide issue.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore the affected users</b>: Affected users are a primary source of scope information.</span><span class='qd'><b>Skip forming a theory</b>: Scope informs the theory; it does not replace it.</span><span class='qd'><b>Avoid documentation</b>: Scope is part of the information documented, not a reason to skip it.</span>" },
  { id:"D4-014", domain:4, obj:"4.1", diff:"easy", q:"Before testing a theory on a critical production server, the safest approach is often to:", options:["Reproduce or test in a non-production environment when possible","Test on production during business hours","Never test theories","Delete production data first"], answer:1, explain:"<strong>Reproduce or test in a non-production environment when possible</strong> testing in a non-production setting protects live services while validating the theory.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Test on production during business hours</b>: Live testing during business hours risks user-facing outages.</span><span class='qd'><b>Never test theories</b>: Testing the theory is a required step of the methodology.</span><span class='qd'><b>Delete production data first</b>: Destroying data is never an appropriate prerequisite to testing.</span>" },
  { id:"D4-015", domain:4, obj:"4.1", diff:"medium", q:"A technician fixes a server but does not verify functionality. What risk does skipping verification create?", options:["None, the fix is guaranteed","The issue may persist or a new issue may go unnoticed","Documentation becomes mandatory","The methodology is shortened correctly"], answer:0, explain:"<strong>The issue may persist or a new issue may go unnoticed</strong> without verifying full functionality, you cannot confirm the fix worked or that it did not introduce side effects.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>None, the fix is guaranteed</b>: No fix is guaranteed without verification.</span><span class='qd'><b>Documentation becomes mandatory</b>: Documentation is always part of the process; skipping verification does not change that.</span><span class='qd'><b>The methodology is shortened correctly</b>: Skipping a step is a deviation from the methodology, not a correct shortcut.</span>" },
  { id:"D4-016", domain:4, obj:"4.1", diff:"hard", q:"After a successful repair, implementing preventive measures might include scheduling regular reboots. The primary benefit of scheduled reboots is to:", options:["Free memory from poorly written apps and clear stuck processes","Permanently disable patching","Reset all user passwords","Increase electricity usage"], answer:3, explain:"<strong>Free memory from poorly written apps and clear stuck processes</strong> scheduled reboots can reclaim leaked memory and kill processes that did not shut down correctly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase electricity usage</b>: Power usage is not a benefit and not the purpose.</span><span class='qd'><b>Permanently disable patching</b>: Reboots typically complete patching rather than disable it.</span><span class='qd'><b>Reset all user passwords</b>: Reboots do not reset credentials.</span>" },
  { id:"D4-017", domain:4, obj:"4.1", diff:"medium", q:"A technician escalates an issue. Escalation is appropriate when:", options:["The problem exceeds the technician's access or expertise","Documentation is complete","The first theory was correct","A user is annoyed"], answer:2, explain:"<strong>The problem exceeds the technician's access or expertise</strong> escalation is warranted when the issue is beyond the technician's permissions, skills, or the systems they control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The first theory was correct</b>: A correct theory means you proceed to a plan, not escalate.</span><span class='qd'><b>Documentation is complete</b>: Completing documentation is the end of a resolved ticket, not a trigger to escalate.</span><span class='qd'><b>A user is annoyed</b>: User frustration alone does not define a technical escalation point.</span>" },
  { id:"D4-018", domain:4, obj:"4.1", diff:"easy", q:"In the methodology, 'establish a theory of probable cause' includes considering:", options:["Obvious and multiple possible causes, questioning the obvious","Ignoring symptoms","Skipping straight to documentation","Only the most expensive cause"], answer:3, explain:"<strong>Obvious and multiple possible causes, questioning the obvious</strong> forming a theory means weighing several plausible causes and not overlooking obvious ones.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only the most expensive cause</b>: Cost is not how you prioritize a probable cause.</span><span class='qd'><b>Ignoring symptoms</b>: Symptoms are the basis for forming a theory.</span><span class='qd'><b>Skipping straight to documentation</b>: Documentation is the last step, not part of theorizing.</span>" },
  { id:"D4-019", domain:4, obj:"4.1", diff:"medium", q:"A sysadmin and a network admin disagree on who owns a problem. Determining whether the issue is OS/application versus network helps because:", options:["Both teams always fix everything together","Ownership never matters","The user fixes it themselves","It assigns the correct team responsibility"], answer:3, explain:"<strong>It assigns the correct team responsibility</strong> because in many shops the sysadmin and network admin roles are split, so identifying the layer routes the ticket to the right group.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Both teams always fix everything together</b>: Defined role splits mean work is divided, not always joint.</span><span class='qd'><b>Ownership never matters</b>: Correct ownership speeds resolution and is part of methodology.</span><span class='qd'><b>The user fixes it themselves</b>: End users do not own server or network infrastructure repairs.</span>" },
  { id:"D4-020", domain:4, obj:"4.1", diff:"hard", q:"A technician must roll back a change that caused an outage. The cleanest rollback option, if available, is to:", options:["Uninstall/remove the change or revert to a snapshot/restore point","Ignore it and move on","Add more RAM","Format the server"], answer:3, explain:"<strong>Uninstall/remove the change or revert to a snapshot/restore point</strong> reverting via uninstall or a pre-change snapshot/restore point cleanly undoes the problematic change.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Format the server</b>: Formatting is destructive overkill for reverting a single change.</span><span class='qd'><b>Ignore it and move on</b>: Ignoring an outage-causing change leaves the system broken.</span><span class='qd'><b>Add more RAM</b>: Adding memory does not undo a misconfiguration or bad change.</span>" },
  { id:"D4-021", domain:4, obj:"4.1", diff:"medium", q:"Which sequence correctly orders the CompTIA troubleshooting steps?", options:["Identify, theorize, test, plan, implement/verify, document","Document, test, identify, plan, theorize, verify","Verify, identify, document, theorize, plan, test","Plan, identify, theorize, test, verify, document"], answer:3, explain:"<strong>Identify, theorize, test, plan, implement/verify, document</strong> this matches the CompTIA order: identify the problem, establish a theory, test the theory, establish a plan, implement and verify, then document.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Plan, identify, theorize, test, verify, document</b>: Planning cannot precede identifying the problem.</span><span class='qd'><b>Document, test, identify, plan, theorize, verify</b>: Documentation is last, not first.</span><span class='qd'><b>Verify, identify, document, theorize, plan, test</b>: You cannot verify a fix before identifying the problem.</span>" },
  { id:"D4-022", domain:4, obj:"4.1", diff:"easy", q:"A technician keeps changing multiple variables at once and cannot tell what fixed the issue. A better practice is to:", options:["Change everything simultaneously","Never test changes","Avoid documenting results","Change one variable at a time"], answer:3, explain:"<strong>Change one variable at a time</strong> isolating one change at a time lets you attribute results and identify the true cause.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Change everything simultaneously</b>: Bulk changes make it impossible to know which one helped.</span><span class='qd'><b>Never test changes</b>: Testing changes is essential to validate a fix.</span><span class='qd'><b>Avoid documenting results</b>: Documentation supports, not hinders, isolating causes.</span>" },
  { id:"D4-023", domain:4, obj:"4.1", diff:"medium", q:"During identification, gathering information from monitoring dashboards and event logs primarily helps to:", options:["Corroborate symptoms with objective data","Eliminate documentation","Replace the need for a theory","Bypass change management"], answer:2, explain:"<strong>Corroborate symptoms with objective data</strong> logs and dashboards provide measurable evidence that supports accurate problem identification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replace the need for a theory</b>: Data informs the theory; it does not eliminate the theorizing step.</span><span class='qd'><b>Eliminate documentation</b>: Documentation is still required at the end.</span><span class='qd'><b>Bypass change management</b>: Evidence gathering does not override change control.</span>" },
  { id:"D4-024", domain:4, obj:"4.1", diff:"hard", q:"A technician notices a fix worked but suspects it only masked the root cause. The most professional response is to:", options:["Close the ticket immediately","Continue investigating the underlying cause and document it","Blame the hardware vendor","Disable monitoring"], answer:0, explain:"<strong>Continue investigating the underlying cause and document it</strong> addressing only symptoms invites recurrence, so identifying and recording the true root cause is best practice.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Close the ticket immediately</b>: Closing without root cause risks the issue returning.</span><span class='qd'><b>Blame the hardware vendor</b>: Assigning blame without evidence is not troubleshooting.</span><span class='qd'><b>Disable monitoring</b>: Monitoring helps detect recurrence and should remain on.</span>" },
  { id:"D4-025", domain:4, obj:"4.1", diff:"medium", q:"A preventive measure after resolving a recurring memory exhaustion issue would most appropriately be:", options:["Scheduling regular reboots and monitoring memory trends","Removing all RAM","Disabling the application permanently","Ignoring future alerts"], answer:0, explain:"<strong>Scheduling regular reboots and monitoring memory trends</strong> preventive measures such as scheduled reboots and trend monitoring reduce recurrence of memory issues.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Removing all RAM</b>: Removing memory would cripple the server, not prevent the issue.</span><span class='qd'><b>Disabling the application permanently</b>: Disabling needed apps is not a measured preventive step.</span><span class='qd'><b>Ignoring future alerts</b>: Ignoring alerts undermines prevention and detection.</span>" },
  { id:"D4-026", domain:4, obj:"4.4", diff:"easy", q:"A Windows server fails to load its GUI after a video driver update, leaving you unable to revert. The best recovery option is to:", options:["Boot into Safe Mode and replace the driver","Replace the motherboard","Reset all user passwords","Reinstall the entire OS"], answer:3, explain:"<strong>Boot into Safe Mode and replace the driver</strong> Safe Mode loads minimal components and bypasses the third-party video driver, letting you install a correct one.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reinstall the entire OS</b>: Reloading the OS is excessive for a single bad driver.</span><span class='qd'><b>Replace the motherboard</b>: The issue is software, not motherboard hardware.</span><span class='qd'><b>Reset all user passwords</b>: Passwords are unrelated to a failed video driver.</span>" },
  { id:"D4-027", domain:4, obj:"4.4", diff:"easy", q:"On a Linux server, the equivalent of Windows Safe Mode that loads minimal drivers and allows only root to log in is:", options:["Multi-user graphical mode","Hibernate mode","Recovery snapshot mode","Single-user mode"], answer:3, explain:"<strong>Single-user mode</strong> Linux single-user mode loads minimal drivers and services and permits only the root account to authenticate to fix startup problems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Multi-user graphical mode</b>: This is the normal full mode, not a minimal recovery mode.</span><span class='qd'><b>Hibernate mode</b>: Hibernate saves state to disk; it is not a minimal-driver recovery mode.</span><span class='qd'><b>Recovery snapshot mode</b>: Snapshots revert state but are not the minimal-driver login mode described.</span>" },
  { id:"D4-028", domain:4, obj:"4.4", diff:"medium", q:"A Linux service was reconfigured by editing its text config file, but the change has not taken effect. The technician should:", options:["Restart the service so it rereads the config","Reinstall the OS","Reboot the entire server","Delete the config file"], answer:2, explain:"<strong>Restart the service so it rereads the config</strong> Linux services read their text config at startup, so restarting the service forces it to reload the new configuration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reboot the entire server</b>: Restarting the whole server is unnecessary downtime when only the service needs reloading.</span><span class='qd'><b>Reinstall the OS</b>: Reinstalling is drastically excessive for a config reload.</span><span class='qd'><b>Delete the config file</b>: Deleting the config removes the very settings you changed.</span>" },
  { id:"D4-029", domain:4, obj:"4.4", diff:"medium", q:"Which systemd command checks the current status of the sshd service on Linux?", options:["systemctl status sshd","service start sshd now","chkconfig sshd reset","ifconfig sshd status"], answer:0, explain:"<strong>systemctl status sshd</strong> systemctl is the systemd tool used to start, stop, restart, enable, disable, and check the status of services.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>service start sshd now</b>: This is not valid systemctl syntax and does not check status.</span><span class='qd'><b>chkconfig sshd reset</b>: chkconfig is legacy and 'reset' is not how you query status.</span><span class='qd'><b>ifconfig sshd status</b>: ifconfig manages network interfaces, not services.</span>" },
  { id:"D4-030", domain:4, obj:"4.4", diff:"hard", q:"Restarting the DNS service on a Windows domain controller also restarts AD Domain Services. This is because:", options:["ADDS depends on the DNS service","DNS and ADDS are unrelated","Windows restarts random services","The registry forces it"], answer:1, explain:"<strong>ADDS depends on the DNS service</strong> service dependencies mean restarting DNS triggers a restart of ADDS, which relies on DNS.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS and ADDS are unrelated</b>: ADDS specifically depends on DNS among other services.</span><span class='qd'><b>Windows restarts random services</b>: Restarts cascade by defined dependencies, not randomly.</span><span class='qd'><b>The registry forces it</b>: Dependency relationships, not raw registry edits, drive the cascade.</span>" },
  { id:"D4-031", domain:4, obj:"4.4", diff:"easy", q:"A Windows service is set so it does not start at boot but can be started when needed. Which startup type is this?", options:["Manual","Automatic","Disabled","Delayed-forced"], answer:1, explain:"<strong>Manual</strong> a Manual service starts only when it is needed rather than at boot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Automatic</b>: Automatic services start when the server boots.</span><span class='qd'><b>Disabled</b>: Disabled services do not start at boot and cannot be started normally.</span><span class='qd'><b>Delayed-forced</b>: This is not the described startup option for on-demand starting.</span>" },
  { id:"D4-032", domain:4, obj:"4.4", diff:"medium", q:"After a patch, a server experiences gradually increasing memory use until services crash. This symptom most likely indicates a:", options:["Memory leak","Healthy cache","Disabled NIC","Clock skew"], answer:0, explain:"<strong>Memory leak</strong> steadily growing memory consumption that eventually exhausts resources is the classic signature of a memory leak, a documented patch-related issue.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Healthy cache</b>: A healthy cache stabilizes; it does not grow until crash.</span><span class='qd'><b>Disabled NIC</b>: A disabled NIC affects connectivity, not memory growth.</span><span class='qd'><b>Clock skew</b>: Clock skew causes time/auth issues, not rising memory.</span>" },
  { id:"D4-033", domain:4, obj:"4.4", diff:"medium", q:"A patch installs but a dependent component breaks afterward across other systems. This is best described as a:", options:["Successful patch","Downstream failure due to updates","Hardware POST error","DHCP scope exhaustion"], answer:1, explain:"<strong>Downstream failure due to updates</strong> when an update breaks dependent components elsewhere, it is a downstream failure caused by the update.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Successful patch</b>: A patch that breaks dependents is not successful.</span><span class='qd'><b>Hardware POST error</b>: POST errors occur at boot from hardware, not from a software patch.</span><span class='qd'><b>DHCP scope exhaustion</b>: Scope exhaustion is an addressing problem unrelated to patch dependencies.</span>" },
  { id:"D4-034", domain:4, obj:"4.4", diff:"hard", q:"In a business environment, the recommended Microsoft service to centrally approve, stage, and report on OS patches is:", options:["WSUS","NTP","DHCP","RAID"], answer:0, explain:"<strong>WSUS</strong> Windows Server Update Service lets administrators manage approval, staged deployment, and reporting for patches.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>NTP</b>: NTP synchronizes time, not patches.</span><span class='qd'><b>DHCP</b>: DHCP assigns IP addresses; it does not manage patching.</span><span class='qd'><b>RAID</b>: RAID provides disk redundancy, unrelated to patch management.</span>" },
  { id:"D4-035", domain:4, obj:"4.4", diff:"medium", q:"The general patch management process is: identify applicable patches, then download/deploy to test systems, then verify, then:", options:["Delete all backups","Disable WSUS","Format the test systems","Deploy patches to destination systems"], answer:3, explain:"<strong>Deploy patches to destination systems</strong> after verifying functionality on test systems, the final step is deploying the patches to the destination production systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete all backups</b>: Removing backups is never a patch step.</span><span class='qd'><b>Disable WSUS</b>: WSUS is used to deploy, not disabled at this stage.</span><span class='qd'><b>Format the test systems</b>: Formatting test systems is not part of the patch workflow.</span>" },
  { id:"D4-036", domain:4, obj:"4.4", diff:"easy", q:"On a Red Hat-derived Linux server, which command installs a software package from a .rpm file?", options:["apt install software.rpm","dpkg -r software.rpm","rpm -ivh software.rpm","yum remove software.rpm"], answer:2, explain:"<strong>rpm -ivh software.rpm</strong> rpm with -ivh installs a package on Red Hat-derived distributions that use .rpm files.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>apt install software.rpm</b>: APT is for Debian-derived distributions, not .rpm installs.</span><span class='qd'><b>dpkg -r software.rpm</b>: dpkg is Debian tooling and -r removes packages.</span><span class='qd'><b>yum remove software.rpm</b>: yum remove uninstalls software rather than installing it.</span>" },
  { id:"D4-037", domain:4, obj:"4.4", diff:"medium", q:"A Debian-derived Linux server needs new software installed from a repository. The correct package tool is:", options:["apt install software-package","rpm -ivh software-package","yum install software-package","systemctl install software-package"], answer:0, explain:"<strong>apt install software-package</strong> Debian-derived distributions use dpkg or APT, so apt install is correct.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rpm -ivh software-package</b>: rpm is for Red Hat-derived distributions.</span><span class='qd'><b>yum install software-package</b>: yum is a Red Hat-derived package manager.</span><span class='qd'><b>systemctl install software-package</b>: systemctl manages services, not package installation.</span>" },
  { id:"D4-038", domain:4, obj:"4.4", diff:"hard", q:"A service will not start, logging an error that a required library is absent. This indicates a:", options:["Missing dependency","Successful boot","DNS timeout","Failover event"], answer:0, explain:"<strong>Missing dependency</strong> a service failing because a needed library or component is absent is a missing dependency problem.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Successful boot</b>: A failed service start is not a successful boot.</span><span class='qd'><b>DNS timeout</b>: DNS timeouts relate to name resolution, not a missing library.</span><span class='qd'><b>Failover event</b>: Failover is a clustering action, not a dependency error.</span>" },
  { id:"D4-039", domain:4, obj:"4.4", diff:"medium", q:"A server cannot write to its system logs after being removed from the domain. A documented cause is:", options:["Too much RAM","A new keyboard","Server not joined to domain","Faster CPU"], answer:2, explain:"<strong>Server not joined to domain</strong> being unjoined from the domain is a documented cause of being unable to write to system logs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Too much RAM</b>: Excess RAM does not block log writes.</span><span class='qd'><b>A new keyboard</b>: Input peripherals are unrelated to log writing.</span><span class='qd'><b>Faster CPU</b>: CPU speed does not determine domain logging permissions.</span>" },
  { id:"D4-040", domain:4, obj:"4.4", diff:"hard", q:"An application throws permission errors when accessing a resource even though the user is valid. A likely cause is:", options:["A perfect configuration","Excess disk space","Inappropriate application-level permissions","A fully patched OS"], answer:2, explain:"<strong>Inappropriate application-level permissions</strong> misconfigured application-level permissions are a documented cause of service failures and resource access errors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A perfect configuration</b>: A perfect config would not produce permission errors.</span><span class='qd'><b>Excess disk space</b>: Free disk space does not cause permission denials.</span><span class='qd'><b>A fully patched OS</b>: Being patched does not by itself cause permission errors.</span>" },
  { id:"D4-041", domain:4, obj:"4.4", diff:"medium", q:"To run a single command as root on Linux without giving a user the root password, an admin should configure:", options:["Full su access for everyone","The /etc/sudoers file for delegated sudo","Disabled logging","A second NIC"], answer:1, explain:"<strong>The /etc/sudoers file for delegated sudo</strong> editing /etc/sudoers lets root delegate specific commands to a user via sudo without sharing the root password.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full su access for everyone</b>: su with the root password grants unrestricted access, the opposite of least privilege.</span><span class='qd'><b>Disabled logging</b>: Disabling logs does not delegate privilege and harms auditing.</span><span class='qd'><b>A second NIC</b>: A NIC is networking hardware, unrelated to privilege delegation.</span>" },
  { id:"D4-042", domain:4, obj:"4.4", diff:"easy", q:"At the Windows command line, which command runs a program as a different user?", options:["runas","sudo","su","chmod"], answer:0, explain:"<strong>runas</strong> the Windows CLI uses runas to execute a command or script as a different user.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>sudo</b>: sudo is a Linux privilege command, not Windows.</span><span class='qd'><b>su</b>: su is the Linux switch-user command.</span><span class='qd'><b>chmod</b>: chmod changes Linux file permissions, not user context.</span>" },
  { id:"D4-043", domain:4, obj:"4.4", diff:"medium", q:"A poorly written application repeatedly writes past its allocated buffer, destabilizing the server. This flaw is a:", options:["Clock skew","RAID rebuild","Buffer overrun","DNS cache miss"], answer:2, explain:"<strong>Buffer overrun</strong> writing beyond an allocated buffer is a buffer overrun, a documented cause of instability and service failures.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Clock skew</b>: Clock skew is a time mismatch, not a memory boundary issue.</span><span class='qd'><b>RAID rebuild</b>: A RAID rebuild is a storage redundancy operation.</span><span class='qd'><b>DNS cache miss</b>: A DNS cache miss is a name-resolution event, not memory corruption.</span>" },
  { id:"D4-044", domain:4, obj:"4.4", diff:"hard", q:"After a patch, a critical service will not start and the patch cannot be uninstalled. The next-best recovery option is to:", options:["Format every disk","Remove all NICs","Roll back to a restore point before the patch","Disable the firewall permanently"], answer:2, explain:"<strong>Roll back to a restore point before the patch</strong> when a patch cannot be removed, reverting to a pre-patch restore point returns the system to a working state.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Format every disk</b>: Formatting destroys data and is far more drastic than a rollback.</span><span class='qd'><b>Remove all NICs</b>: Removing network cards does not address a bad patch.</span><span class='qd'><b>Disable the firewall permanently</b>: Disabling the firewall is a security risk and unrelated to the patch.</span>" },
  { id:"D4-045", domain:4, obj:"4.4", diff:"medium", q:"A host-based firewall on a Windows server applies stricter rules at a coffee shop than at the office. This behavior is controlled by firewall:", options:["RAID levels","Zones (Domain vs Public)","NTP strata","DHCP scopes"], answer:1, explain:"<strong>Zones (Domain vs Public)</strong> host-based firewalls use zones, applying the trusted Domain zone on the business network and the stricter Public zone elsewhere.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RAID levels</b>: RAID levels concern disk redundancy, not firewall rules.</span><span class='qd'><b>NTP strata</b>: NTP strata describe time-source hierarchy.</span><span class='qd'><b>DHCP scopes</b>: DHCP scopes define IP address ranges, not firewall trust zones.</span>" },
  { id:"D4-046", domain:4, obj:"4.4", diff:"easy", q:"Kerberos authentication can fail when server clocks disagree. The protocol that synchronizes time across the network is:", options:["HTTP","SNMP","NTP","SMTP"], answer:2, explain:"<strong>NTP</strong> Network Time Protocol synchronizes time, which services like Kerberos rely on for valid timestamps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>HTTP</b>: HTTP serves web content, not time sync.</span><span class='qd'><b>SNMP</b>: SNMP is for network monitoring/management.</span><span class='qd'><b>SMTP</b>: SMTP transports email.</span>" },
  { id:"D4-047", domain:4, obj:"4.4", diff:"medium", q:"A server's clock drifts because its motherboard battery failed and it is not syncing time. A likely consequence is:", options:["Clock skew causing authentication failures","Faster disk reads","More available RAM","Improved network speed"], answer:0, explain:"<strong>Clock skew causing authentication failures</strong> a failed CMOS battery and lost time sync produce clock skew, which breaks timestamp-dependent services like Kerberos.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Faster disk reads</b>: Clock accuracy does not speed up disks.</span><span class='qd'><b>More available RAM</b>: Time drift does not free memory.</span><span class='qd'><b>Improved network speed</b>: Clock skew degrades auth, not improves throughput.</span>" },
  { id:"D4-048", domain:4, obj:"4.4", diff:"hard", q:"A configuration management approach where admins declare a desired state and tools enforce it (e.g., Puppet, Chef, Ansible) primarily improves:", options:["Consistent, repeatable OS configuration","Physical cable runs","CPU clock speed","Tape capacity"], answer:0, explain:"<strong>Consistent, repeatable OS configuration</strong> orchestration tools enforce a declared desired configuration so systems match it consistently.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physical cable runs</b>: These tools manage software/config, not physical cabling.</span><span class='qd'><b>CPU clock speed</b>: They do not change processor frequency.</span><span class='qd'><b>Tape capacity</b>: Backup media capacity is unrelated to config management tools.</span>" },
  { id:"D4-049", domain:4, obj:"4.4", diff:"medium", q:"A technician needs to revert a VM to a known-good state before a botched change. The fastest option is usually to:", options:["Restore from a VM snapshot","Reinstall the OS from scratch","Replace the host server","Re-cable the network"], answer:0, explain:"<strong>Restore from a VM snapshot</strong> virtualization snapshots capture a point-in-time state, letting you roll a VM back quickly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reinstall the OS from scratch</b>: A full reinstall is far slower than a snapshot revert.</span><span class='qd'><b>Replace the host server</b>: Hardware replacement is unnecessary for a config rollback.</span><span class='qd'><b>Re-cable the network</b>: Cabling does not undo a guest configuration change.</span>" },
  { id:"D4-050", domain:4, obj:"4.4", diff:"medium", q:"A best practice to limit risk is to avoid signing in to a server with administrative credentials and instead:", options:["Share the admin password widely","Disable all accounts","Log in as a standard user and elevate when necessary","Always log in as root"], answer:2, explain:"<strong>Log in as a standard user and elevate when necessary</strong> least-privilege practice is to operate as a non-privileged user and elevate only when required.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Share the admin password widely</b>: Sharing admin credentials increases risk dramatically.</span><span class='qd'><b>Disable all accounts</b>: Disabling all accounts would lock everyone out.</span><span class='qd'><b>Always log in as root</b>: Persistent root login is exactly the risky behavior to avoid.</span>" },
  { id:"D4-051", domain:4, obj:"4.3", diff:"easy", q:"When troubleshooting network connectivity, what is generally the best first thing to verify?", options:["DNS resolution","Physical connectivity (link lights, cables, power)","Route tables","Application permissions"], answer:1, explain:"<strong>Physical connectivity (link lights, cables, power)</strong> it is best to verify physical connectivity, such as link lights and cable integrity, before using software tools.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS resolution</b>: Name resolution is checked later, after physical and IP layers.</span><span class='qd'><b>Route tables</b>: Routing is examined after confirming physical and basic IP connectivity.</span><span class='qd'><b>Application permissions</b>: App permissions are an OS/app concern, not the first network check.</span>" },
  { id:"D4-052", domain:4, obj:"4.3", diff:"medium", q:"A technician must determine whether a connectivity problem is internal or external. An external issue usually involves:", options:["Accessing Internet or cloud resources","A single internal client only","Local file permissions","CPU affinity"], answer:0, explain:"<strong>Accessing Internet or cloud resources</strong> external issues typically involve reaching the Internet or cloud-based resources, while internal issues stay inside the LAN.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single internal client only</b>: That describes an internal, locally contained issue.</span><span class='qd'><b>Local file permissions</b>: File permissions are an OS concern, not external connectivity.</span><span class='qd'><b>CPU affinity</b>: CPU affinity is a processor scheduling setting, unrelated to network scope.</span>" },
  { id:"D4-053", domain:4, obj:"4.3", diff:"medium", q:"On Windows, which command displays the current IP configuration?", options:["ifconfig","ip addr","ipconfig","route show linux"], answer:2, explain:"<strong>ipconfig</strong> ipconfig confirms basic IP configuration on Windows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ifconfig</b>: ifconfig is a Linux/Unix tool, not Windows.</span><span class='qd'><b>ip addr</b>: ip addr is a Linux command for interface addresses.</span><span class='qd'><b>route show linux</b>: This is not a valid Windows command for IP config display.</span>" },
  { id:"D4-054", domain:4, obj:"4.3", diff:"easy", q:"On Linux, which commands display interface IP configuration?", options:["ifconfig or ip addr","ipconfig","nslookup only","tracert"], answer:0, explain:"<strong>ifconfig or ip addr</strong> Linux uses ifconfig or ip addr to confirm interface IP configuration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ipconfig</b>: ipconfig is the Windows equivalent.</span><span class='qd'><b>nslookup only</b>: nslookup queries DNS, not interface configuration.</span><span class='qd'><b>tracert</b>: tracert is a Windows path-tracing tool, not an IP display tool.</span>" },
  { id:"D4-055", domain:4, obj:"4.3", diff:"medium", q:"Following the recommended order, after verifying physical and IP configuration you test connectivity by pinging in which order?", options:["Only the router, never the destination","Destination first, then router, then same subnet","Random hosts on the Internet","The DNS root servers first"], answer:1, explain:"<strong>Destination first, then router, then same subnet</strong> the documented order is to ping the destination first, then the router, then a host on the same subnet.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only the router, never the destination</b>: The destination is pinged first in the documented sequence.</span><span class='qd'><b>Random hosts on the Internet</b>: Testing follows a structured local-to-remote order, not random hosts.</span><span class='qd'><b>The DNS root servers first</b>: Root servers are not part of this basic connectivity test order.</span>" },
  { id:"D4-056", domain:4, obj:"4.3", diff:"hard", q:"A ping returns 'Destination host unreachable.' Per the troubleshooting guidance, this is usually a:", options:["Always a DNS failure","Misconfiguration of the ping sender","Hardware POST error","RAID degradation"], answer:1, explain:"<strong>Misconfiguration of the ping sender</strong> 'Destination host unreachable' is usually a misconfiguration of the ping sender.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Always a DNS failure</b>: DNS issues typically show as 'Unknown host,' not this message.</span><span class='qd'><b>Hardware POST error</b>: POST errors occur at boot, not during a ping.</span><span class='qd'><b>RAID degradation</b>: RAID status is unrelated to ICMP reachability messages.</span>" },
  { id:"D4-057", domain:4, obj:"4.3", diff:"medium", q:"A ping by hostname returns 'Unknown host.' This most likely indicates a:", options:["Power supply failure","Name resolution issue","Disk fragmentation","CPU overheating"], answer:1, explain:"<strong>Name resolution issue</strong> 'Unknown host' points to a name resolution problem rather than a routing or hardware fault.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Power supply failure</b>: Power problems do not produce DNS name errors.</span><span class='qd'><b>Disk fragmentation</b>: Fragmentation is a storage performance topic, not name resolution.</span><span class='qd'><b>CPU overheating</b>: Thermal issues do not cause 'Unknown host' messages.</span>" },
  { id:"D4-058", domain:4, obj:"4.3", diff:"medium", q:"A ping returns 'Timeout' but other hosts respond. Guidance says this is usually a:", options:["Misconfiguration of the ping sender","Definitely a cut cable","NTP stratum error","Misconfiguration of the ping destination"], answer:3, explain:"<strong>Misconfiguration of the ping destination</strong> a 'Timeout' is usually a misconfiguration of the ping destination.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Misconfiguration of the ping sender</b>: That symptom maps to 'Destination host unreachable,' not timeout.</span><span class='qd'><b>Definitely a cut cable</b>: A timeout can have many causes; it is not definitively a cut cable.</span><span class='qd'><b>NTP stratum error</b>: Time-source hierarchy is unrelated to ping timeouts.</span>" },
  { id:"D4-059", domain:4, obj:"4.3", diff:"easy", q:"To trace the path packets take to a remote host on Windows, a technician uses:", options:["tracert","traceroute","route add","nbtstat -path"], answer:0, explain:"<strong>tracert</strong> Windows uses tracert to verify the network path to a destination; Linux uses traceroute.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>traceroute</b>: traceroute is the Linux variant, not Windows.</span><span class='qd'><b>route add</b>: route add modifies routing tables, it does not trace a path.</span><span class='qd'><b>nbtstat -path</b>: nbtstat shows NetBIOS info, not a hop-by-hop path.</span>" },
  { id:"D4-060", domain:4, obj:"4.3", diff:"medium", q:"Clients are receiving no IP address from the DHCP server, which is across a router from them. A likely cause is:", options:["Too many NICs","DHCP server on the other side of a router from clients (no relay)","A fast CPU","A new monitor"], answer:1, explain:"<strong>DHCP server on the other side of a router from clients (no relay)</strong> a DHCP server separated from clients by a router (without a relay) is a documented cause of clients receiving no DHCP information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Too many NICs</b>: NIC count does not block cross-subnet DHCP.</span><span class='qd'><b>A fast CPU</b>: CPU speed is unrelated to DHCP delivery.</span><span class='qd'><b>A new monitor</b>: Display hardware has no role in DHCP.</span>" },
  { id:"D4-061", domain:4, obj:"4.3", diff:"hard", q:"On a Windows AD network, clients get no addresses even though the DHCP service is running. A documented cause is:", options:["RAID 0 failure","DHCP server not authorized in Active Directory","Excess RAM","Clock perfectly synced"], answer:1, explain:"<strong>DHCP server not authorized in Active Directory</strong> an unauthorized DHCP server in AD will not lease addresses, a documented cause of missing DHCP information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RAID 0 failure</b>: RAID issues affect storage, not DHCP authorization.</span><span class='qd'><b>Excess RAM</b>: Memory amount does not affect AD authorization.</span><span class='qd'><b>Clock perfectly synced</b>: Correct time would not prevent leasing.</span>" },
  { id:"D4-062", domain:4, obj:"4.3", diff:"medium", q:"To release and renew a Linux client's DHCP lease, which commands are appropriate?", options:["ipconfig /release then ipconfig /renew","systemctl renew dhcp","nslookup -renew","sudo dhclient -r then sudo dhclient"], answer:3, explain:"<strong>sudo dhclient -r then sudo dhclient</strong> on Linux, dhclient -r releases and dhclient requests a new lease.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ipconfig /release then ipconfig /renew</b>: Those are the Windows commands, not Linux.</span><span class='qd'><b>systemctl renew dhcp</b>: systemctl manages services and has no 'renew dhcp' action.</span><span class='qd'><b>nslookup -renew</b>: nslookup queries DNS and cannot renew leases.</span>" },
  { id:"D4-063", domain:4, obj:"4.3", diff:"medium", q:"Hosts on a switch cannot reach each other as expected, and the cause is traced to incorrect VLAN assignment. This is a:", options:["DNS failure","Power outage","CPU affinity error","VLAN misconfiguration"], answer:3, explain:"<strong>VLAN misconfiguration</strong> incorrect VLAN assignment is a documented internal cause of resources being unavailable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS failure</b>: DNS issues affect name resolution, not VLAN membership.</span><span class='qd'><b>Power outage</b>: Power loss would down the devices entirely, not cause selective VLAN isolation.</span><span class='qd'><b>CPU affinity error</b>: CPU affinity is a processor setting, unrelated to VLANs.</span>" },
  { id:"D4-064", domain:4, obj:"4.3", diff:"hard", q:"A server cannot reach hosts on a remote subnet, though local connectivity works. The most likely cause is:", options:["Router or OS route table misconfiguration","A failed monitor","Too little tape capacity","A disabled screensaver"], answer:0, explain:"<strong>Router or OS route table misconfiguration</strong> inability to reach remote subnets while local works points to router misconfiguration or bad OS route tables.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A failed monitor</b>: Monitors do not affect routing.</span><span class='qd'><b>Too little tape capacity</b>: Backup media is unrelated to subnet routing.</span><span class='qd'><b>A disabled screensaver</b>: Screensaver settings have no networking role.</span>" },
  { id:"D4-065", domain:4, obj:"4.3", diff:"medium", q:"To display the server's current active network connections, a technician uses:", options:["nslookup","route delete","dig","netstat"], answer:3, explain:"<strong>netstat</strong> netstat displays current network connections to the server (nbtstat shows NetBIOS info).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>nslookup</b>: nslookup queries DNS records, not active connections.</span><span class='qd'><b>route delete</b>: route delete removes routes; it does not list connections.</span><span class='qd'><b>dig</b>: dig is a DNS lookup tool.</span>" },
  { id:"D4-066", domain:4, obj:"4.3", diff:"easy", q:"To verify name resolution on a server, which tools are appropriate?", options:["nslookup, dig, or host","ipconfig only","route print","netstat -e"], answer:0, explain:"<strong>nslookup, dig, or host</strong> name resolution is verified with nslookup, dig, host, or ping by hostname.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ipconfig only</b>: ipconfig shows IP config, not detailed DNS query results.</span><span class='qd'><b>route print</b>: route print shows the routing table, not name resolution.</span><span class='qd'><b>netstat -e</b>: netstat -e shows interface statistics, not DNS resolution.</span>" },
  { id:"D4-067", domain:4, obj:"4.3", diff:"hard", q:"Users cannot browse the web and cannot reach cloud apps, but internal resources work. Among external causes, which is plausible?", options:["A bad VLAN on an internal switch only","Failure of the service provider or misconfigured edge router","An internal DHCP relay","A local hosts file typo for an internal server"], answer:1, explain:"<strong>Failure of the service provider or misconfigured edge router</strong> loss of Internet/cloud access while internal works points to external causes like ISP failure or edge router misconfiguration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A bad VLAN on an internal switch only</b>: Internal VLAN problems would affect internal connectivity, which is working.</span><span class='qd'><b>An internal DHCP relay</b>: A relay issue would affect internal addressing, not specifically Internet access.</span><span class='qd'><b>A local hosts file typo for an internal server</b>: A hosts entry for an internal server would not block all Internet/cloud access.</span>" },
  { id:"D4-068", domain:4, obj:"4.3", diff:"medium", q:"A NIC shows no link light and the cable seems loose. The most direct fix aligns with which troubleshooting step?", options:["Verify name resolution","Update route tables","Check application permissions","Verify physical connectivity"], answer:3, explain:"<strong>Verify physical connectivity</strong> a missing link light and loose cable are physical-layer issues addressed by verifying physical connectivity first.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Verify name resolution</b>: DNS checks come after physical connectivity is confirmed.</span><span class='qd'><b>Update route tables</b>: Routing is a later step than physical verification.</span><span class='qd'><b>Check application permissions</b>: Permissions are an OS/app concern, not a cable problem.</span>" },
  { id:"D4-069", domain:4, obj:"4.3", diff:"medium", q:"A static IP was entered with the wrong subnet mask, causing a host to be unreachable. This is best categorized as:", options:["Improper IP configuration due to a static assignment mistake","DHCP exhaustion","A failed router","A DNS server crash"], answer:0, explain:"<strong>Improper IP configuration due to a static assignment mistake</strong> a wrong manually entered subnet mask is improper IP configuration from a static assignment error.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DHCP exhaustion</b>: The address was set statically, so DHCP scope is not involved.</span><span class='qd'><b>A failed router</b>: A single misconfigured host is not a router failure.</span><span class='qd'><b>A DNS server crash</b>: Name resolution is separate from a bad static mask.</span>" },
  { id:"D4-070", domain:4, obj:"4.3", diff:"hard", q:"A technician wants to test whether a specific TCP port on a remote server is open during connectivity testing. A suitable tool is:", options:["ipconfig /all","dig +short","route print","nc (netcat) or telnet"], answer:3, explain:"<strong>nc (netcat) or telnet</strong> netcat and telnet can test connectivity to a specific port on a destination.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ipconfig /all</b>: ipconfig shows configuration, not port reachability.</span><span class='qd'><b>dig +short</b>: dig queries DNS records, not TCP ports.</span><span class='qd'><b>route print</b>: route print lists routes, not open ports.</span>" },
  { id:"D4-071", domain:4, obj:"4.3", diff:"medium", q:"Switch port security was configured incorrectly, blocking a server's MAC from communicating. This is documented as a cause of:", options:["Faster backups","Better DNS","Lower CPU usage","Resource unavailability on the internal network"], answer:3, explain:"<strong>Resource unavailability on the internal network</strong> network port security misconfigured at the switch is a documented internal cause of unavailable resources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Faster backups</b>: Port security misconfiguration does not speed backups.</span><span class='qd'><b>Better DNS</b>: It does not improve name resolution.</span><span class='qd'><b>Lower CPU usage</b>: It is unrelated to processor load.</span>" },
  { id:"D4-072", domain:4, obj:"4.3", diff:"easy", q:"Which tool resolves a hostname to an IP and can query specific DNS record types interactively?", options:["netstat","tracert","ifconfig","nslookup"], answer:3, explain:"<strong>nslookup</strong> nslookup is a name-resolution tool used to query DNS for hostnames and record types.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>netstat</b>: netstat shows connections and statistics, not DNS queries.</span><span class='qd'><b>tracert</b>: tracert traces network paths.</span><span class='qd'><b>ifconfig</b>: ifconfig shows interface configuration on Linux.</span>" },
  { id:"D4-073", domain:4, obj:"4.3", diff:"hard", q:"Multiple internal symptoms (ping failures, failed name resolution, no DHCP) appear together. The technician should FIRST suspect:", options:["Each symptom is unrelated","A common upstream cause like a core switch, DHCP/DNS server, or cabling","A user's keyboard","An application bug only"], answer:1, explain:"<strong>A common upstream cause like a core switch, DHCP/DNS server, or cabling</strong> correlated internal failures often share a single upstream cause that should be investigated before chasing each symptom separately.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Each symptom is unrelated</b>: Treating correlated failures as unrelated wastes time and misses the shared root.</span><span class='qd'><b>A user's keyboard</b>: Input hardware does not cause network-wide failures.</span><span class='qd'><b>An application bug only</b>: A single app bug would not produce DHCP, DNS, and ping failures together.</span>" },
  { id:"D4-074", domain:4, obj:"4.3", diff:"medium", q:"After fixing a DNS server, a technician confirms resolution works by pinging hosts by hostname. This validates which troubleshooting goal?", options:["Verify name resolution","Verify cable integrity","Verify power supply","Verify CPU affinity"], answer:0, explain:"<strong>Verify name resolution</strong> pinging by hostname confirms name resolution is functioning.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Verify cable integrity</b>: Cable checks are physical-layer, not DNS validation.</span><span class='qd'><b>Verify power supply</b>: Power confirmation is a physical step, unrelated to DNS.</span><span class='qd'><b>Verify CPU affinity</b>: CPU affinity is a processor setting, not name resolution.</span>" },
  { id:"D4-075", domain:4, obj:"4.2", diff:"easy", q:"The 3-2-1 backup rule recommends keeping how many copies of data?", options:["One copy on one tape","Five copies all on-site","Three copies, on two media types, with one off-site","Two copies on the same disk"], answer:2, explain:"<strong>Three copies, on two media types, with one off-site</strong> the 3-2-1 rule keeps three copies of data on two different media with one copy stored off-site.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>One copy on one tape</b>: A single copy provides no redundancy and violates 3-2-1.</span><span class='qd'><b>Five copies all on-site</b>: On-site-only copies fail the off-site requirement.</span><span class='qd'><b>Two copies on the same disk</b>: Same-media copies fail the two-media-types requirement.</span>" },
  { id:"D4-076", domain:4, obj:"4.2", diff:"medium", q:"A backup that captures only changes since the last backup and resets the archive bit is a:", options:["Differential backup","Full backup","Incremental backup","Synthetic full backup"], answer:2, explain:"<strong>Incremental backup</strong> an incremental backs up changes since the last marker and resets the archive bit, yielding fast backups but slower restores.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Differential backup</b>: A differential does not reset the archive bit.</span><span class='qd'><b>Full backup</b>: A full backup copies everything, not just changes.</span><span class='qd'><b>Synthetic full backup</b>: A synthetic full is assembled from a full plus incrementals, not a single change-only job.</span>" },
  { id:"D4-077", domain:4, obj:"4.2", diff:"medium", q:"A backup that captures all changes since the last full backup without resetting the archive bit is a:", options:["Incremental backup","Snapshot","Archive","Differential backup"], answer:3, explain:"<strong>Differential backup</strong> a differential backs up changes since the last full and does not reset the archive bit, so restores need only the full plus the latest differential.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Incremental backup</b>: An incremental resets the archive bit and needs every job since the full to restore.</span><span class='qd'><b>Snapshot</b>: A snapshot is a point-in-time read-only copy, not a differential job.</span><span class='qd'><b>Archive</b>: Archives are for long-term retention, not change-based backup jobs.</span>" },
  { id:"D4-078", domain:4, obj:"4.2", diff:"hard", q:"An organization values the fastest possible restore. Which scheme should it choose?", options:["Full plus incremental","Incremental only","No backups","Full plus differential"], answer:3, explain:"<strong>Full plus differential</strong> Full+Differential gives faster restores because only two jobs (the full and latest differential) are needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full plus incremental</b>: Full+Incremental restores are slower because every incremental since the full must be applied.</span><span class='qd'><b>Incremental only</b>: Incrementals alone have no base full and are not a valid standalone restore scheme here.</span><span class='qd'><b>No backups</b>: No backups means no restore at all.</span>" },
  { id:"D4-079", domain:4, obj:"4.2", diff:"hard", q:"An organization values the fastest possible nightly backup window and accepts slower restores. The best scheme is:", options:["Full plus differential","Full plus incremental","Full every night","Differential only"], answer:1, explain:"<strong>Full plus incremental</strong> Full+Incremental yields fast backups because each incremental copies only the latest changes, trading off slower restores.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full plus differential</b>: Differentials grow larger as the week progresses, slowing backups compared to incrementals.</span><span class='qd'><b>Full every night</b>: Nightly full backups are the slowest backup option.</span><span class='qd'><b>Differential only</b>: Differential-only without a base full is not a valid complete scheme.</span>" },
  { id:"D4-080", domain:4, obj:"4.2", diff:"medium", q:"RPO (Recovery Point Objective) primarily defines:", options:["How long recovery may take","The maximum acceptable amount of data loss measured in time","The cost of a hot site","The number of NICs in a team"], answer:1, explain:"<strong>The maximum acceptable amount of data loss measured in time</strong> RPO expresses how much data, in time, the organization can afford to lose, guiding backup frequency.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>How long recovery may take</b>: That describes RTO, not RPO.</span><span class='qd'><b>The cost of a hot site</b>: Site cost is a DR budgeting concern, not RPO.</span><span class='qd'><b>The number of NICs in a team</b>: NIC teaming is unrelated to RPO.</span>" },
  { id:"D4-081", domain:4, obj:"4.2", diff:"medium", q:"RTO (Recovery Time Objective) primarily defines:", options:["The maximum acceptable data loss","The backup media type","The maximum acceptable time to restore service","The VLAN ID"], answer:2, explain:"<strong>The maximum acceptable time to restore service</strong> RTO is the target time within which service must be restored after an incident.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The maximum acceptable data loss</b>: That is the RPO, not the RTO.</span><span class='qd'><b>The backup media type</b>: Media choice is separate from the time objective.</span><span class='qd'><b>The VLAN ID</b>: VLAN identifiers are unrelated to recovery time.</span>" },
  { id:"D4-082", domain:4, obj:"4.2", diff:"easy", q:"A disaster recovery site that is fully equipped and ready to take over immediately is a:", options:["Cold site","Warm site","Paper site","Hot site"], answer:3, explain:"<strong>Hot site</strong> a hot site has all equipment and replicated data ready for immediate takeover, making it the most expensive but fastest option.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cold site</b>: A cold site has only space and utilities, requiring equipment to be brought in.</span><span class='qd'><b>Warm site</b>: A warm site has some equipment but still needs setup and data migration.</span><span class='qd'><b>Paper site</b>: 'Paper site' is not a DR site type; a paper test is a DR test method.</span>" },
  { id:"D4-083", domain:4, obj:"4.2", diff:"easy", q:"A DR site that is essentially just building space with power and HVAC but no equipment is a:", options:["Hot site","Warm site","Cold site","Cloud site"], answer:2, explain:"<strong>Cold site</strong> a cold site provides space, power, and HVAC only; equipment and data must be brought in before it can operate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hot site</b>: A hot site is fully equipped and ready immediately.</span><span class='qd'><b>Warm site</b>: A warm site already has some hardware in place.</span><span class='qd'><b>Cloud site</b>: A cloud DR site relies on a CSP rather than empty building space.</span>" },
  { id:"D4-084", domain:4, obj:"4.2", diff:"medium", q:"A warm site differs from hot and cold sites because it:", options:["Has space and some equipment but needs setup and data migration","Is fully operational instantly","Has no power or HVAC","Requires no data migration ever"], answer:0, explain:"<strong>Has space and some equipment but needs setup and data migration</strong> a warm site contains space and some hardware but still requires configuration and data migration, costing less than a hot site.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Is fully operational instantly</b>: Instant takeover describes a hot site.</span><span class='qd'><b>Has no power or HVAC</b>: Even cold sites provide power and HVAC; warm sites have more.</span><span class='qd'><b>Requires no data migration ever</b>: Warm sites do require data to be migrated before takeover.</span>" },
  { id:"D4-085", domain:4, obj:"4.2", diff:"hard", q:"In a failover cluster, when the active node fails and the passive node takes over its duties, this event is called:", options:["Failback","Replication","Failover","Load balancing"], answer:2, explain:"<strong>Failover</strong> failover is the passive node assuming the active node's responsibilities after the active node fails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Failback</b>: Failback is returning service to the original node afterward.</span><span class='qd'><b>Replication</b>: Replication copies data, it is not the takeover event.</span><span class='qd'><b>Load balancing</b>: Load balancing distributes work; it is distinct from failover.</span>" },
  { id:"D4-086", domain:4, obj:"4.2", diff:"medium", q:"After a failed node is repaired, shifting services back to it so it resumes its original active role is called:", options:["Failback","Failover","Mirroring","Sharding"], answer:0, explain:"<strong>Failback</strong> failback returns service to the original active node once it is back online.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Failover</b>: Failover is the initial takeover by the passive node, not the return.</span><span class='qd'><b>Mirroring</b>: Mirroring duplicates a database for availability, not role return.</span><span class='qd'><b>Sharding</b>: Sharding partitions data and is unrelated to cluster role return.</span>" },
  { id:"D4-087", domain:4, obj:"4.2", diff:"easy", q:"A two-node cluster where only one node handles requests until the other takes over on failure is:", options:["Active-active","Round robin","Tower of Hanoi","Active-passive"], answer:3, explain:"<strong>Active-passive</strong> in active-passive clustering all requests go to the active node, and the passive node takes over only if the active fails, providing high availability without load balancing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Active-active</b>: Active-active distributes load across both nodes via a load balancer.</span><span class='qd'><b>Round robin</b>: Round robin is a load-balancing schedule, not a cluster mode.</span><span class='qd'><b>Tower of Hanoi</b>: Tower of Hanoi is a backup media rotation scheme.</span>" },
  { id:"D4-088", domain:4, obj:"4.2", diff:"medium", q:"An active-active cluster differs from active-passive because it:", options:["Keeps the second node idle","Uses a load balancer to distribute work across nodes, adding performance","Has only one node","Eliminates the need for backups"], answer:1, explain:"<strong>Uses a load balancer to distribute work across nodes, adding performance</strong> active-active clusters use a load balancer to spread requests across nodes, providing both high availability and increased performance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keeps the second node idle</b>: An idle standby describes active-passive, not active-active.</span><span class='qd'><b>Has only one node</b>: Clusters require at least two nodes.</span><span class='qd'><b>Eliminates the need for backups</b>: Clustering provides availability, not a backup replacement.</span>" },
  { id:"D4-089", domain:4, obj:"4.2", diff:"hard", q:"How should administrators patch a two-node failover cluster to preserve availability?", options:["Bring down both nodes simultaneously","Never patch clusters","Bring down one node at a time, patch and reboot, then return it before doing the other","Patch only the storage array"], answer:2, explain:"<strong>Bring down one node at a time, patch and reboot, then return it before doing the other</strong> patching one node at a time keeps the service available and never brings the whole cluster down at once.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bring down both nodes simultaneously</b>: Downing all nodes at once causes a full outage.</span><span class='qd'><b>Never patch clusters</b>: Clusters still require patching for stability and security.</span><span class='qd'><b>Patch only the storage array</b>: The cluster nodes themselves must be patched, not just storage.</span>" },
  { id:"D4-090", domain:4, obj:"4.2", diff:"medium", q:"To validate that backups are actually recoverable, a low-cost recommended method is to:", options:["Assume backups always work","Never test restores","Delete the backups to save space","Restore data to a VM and verify, then delete the VM"], answer:3, explain:"<strong>Restore data to a VM and verify, then delete the VM</strong> spinning up a VM, restoring data to it, and validating is a quick, cheap way to test backup recoverability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume backups always work</b>: Untested backups frequently fail when needed.</span><span class='qd'><b>Never test restores</b>: Testing restores is essential to prove recoverability.</span><span class='qd'><b>Delete the backups to save space</b>: Deleting backups removes the data you are trying to protect.</span>" },
  { id:"D4-091", domain:4, obj:"4.2", diff:"easy", q:"When testing a restore while production is still in use, the safest restore target is:", options:["Overwrite production","Directly into the live database","An alternate location","The original files in place"], answer:2, explain:"<strong>An alternate location</strong> restoring to an alternate location lets you test recovery without disturbing the live production environment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Overwrite production</b>: Overwriting live data during a test risks destroying current data.</span><span class='qd'><b>Directly into the live database</b>: Restoring into the live database could corrupt active data.</span><span class='qd'><b>The original files in place</b>: Restoring over the originals defeats the purpose of a non-disruptive test.</span>" },
  { id:"D4-092", domain:4, obj:"4.2", diff:"medium", q:"A restore that places recovered data next to existing data so you can compare versions is called:", options:["Side-by-side restore","Overwrite restore","Alternate-location restore","Bare-metal restore"], answer:0, explain:"<strong>Side-by-side restore</strong> a side-by-side restore puts backed-up files alongside current files on the same server for comparison without overwriting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Overwrite restore</b>: An overwrite replaces existing data rather than comparing.</span><span class='qd'><b>Alternate-location restore</b>: An alternate-location restore targets a different system entirely.</span><span class='qd'><b>Bare-metal restore</b>: Bare-metal restores rebuild a whole system from scratch.</span>" },
  { id:"D4-093", domain:4, obj:"4.2", diff:"hard", q:"With asynchronous replication, a risk if the primary fails right after acknowledging a write is that:", options:["Both copies are always identical","Replication cannot fail","The client is never acknowledged","The secondary may not yet have the data, causing data loss"], answer:3, explain:"<strong>The secondary may not yet have the data, causing data loss</strong> async replication acknowledges the client before the secondary confirms, so a primary failure can lose not-yet-replicated data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Both copies are always identical</b>: Async replication has a lag window where copies differ.</span><span class='qd'><b>Replication cannot fail</b>: Replication can and does fail; that is the risk described.</span><span class='qd'><b>The client is never acknowledged</b>: Async specifically acknowledges the client early, before the secondary commits.</span>" },
  { id:"D4-094", domain:4, obj:"4.2", diff:"medium", q:"Synchronous replication ensures consistency because:", options:["Only the primary needs the data","It never confirms writes","It uses tape rotation","The client is not told the write succeeded until both servers have the data"], answer:3, explain:"<strong>The client is not told the write succeeded until both servers have the data</strong> synchronous replication delays acknowledgment until both copies are written, preventing the data loss async risks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only the primary needs the data</b>: Both servers must have the data before acknowledgment in synchronous replication.</span><span class='qd'><b>It never confirms writes</b>: Synchronous replication does confirm, just after both copies exist.</span><span class='qd'><b>It uses tape rotation</b>: Tape rotation schemes are unrelated to replication mode.</span>" },
  { id:"D4-095", domain:4, obj:"4.2", diff:"medium", q:"A backup media rotation that uses three sets and is efficient for archiving older data is the:", options:["First-In First-Out (FIFO)","Tower of Hanoi","Round robin","RAID 5"], answer:1, explain:"<strong>Tower of Hanoi</strong> the Tower of Hanoi rotation uses three backup sets and is an effective archiving scheme, though less efficient for recent restores.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>First-In First-Out (FIFO)</b>: FIFO simply reuses the oldest tape and is not the three-set archiving scheme.</span><span class='qd'><b>Round robin</b>: Round robin is a load-balancing schedule, not a media rotation.</span><span class='qd'><b>RAID 5</b>: RAID 5 is disk redundancy, not backup media rotation.</span>" },
  { id:"D4-096", domain:4, obj:"4.2", diff:"easy", q:"In a Grandfather-Father-Son rotation, the daily backups are referred to as the:", options:["Fathers","Grandfathers","Sons","Cousins"], answer:2, explain:"<strong>Sons</strong> in GFS, the most recent daily backups are the sons, weekly fulls are fathers, and monthly fulls are grandfathers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fathers</b>: Fathers are the weekly full backups.</span><span class='qd'><b>Grandfathers</b>: Grandfathers are the monthly full backups.</span><span class='qd'><b>Cousins</b>: 'Cousins' is not a role in the GFS scheme.</span>" },
  { id:"D4-097", domain:4, obj:"4.2", diff:"hard", q:"A DR test where stakeholders only read and discuss procedures, making no changes and restoring no data, is a:", options:["Paper test","Live failover","Parallel recovery","Cutover test"], answer:0, explain:"<strong>Paper test</strong> a paper test has critical stakeholders examine the procedures and offer suggestions without performing any recovery actions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Live failover</b>: A live failover (cutover) tests on the real production environment.</span><span class='qd'><b>Parallel recovery</b>: Parallel recovery actually executes procedures in a non-production environment.</span><span class='qd'><b>Cutover test</b>: A cutover is the live failover test, which does perform recovery.</span>" },
  { id:"D4-098", domain:4, obj:"4.2", diff:"medium", q:"A DR test executed in a non-production environment (often using VMs) while production stays unaffected is:", options:["Paper test","Parallel recovery using a non-production test environment","Walk-through","Tabletop only"], answer:1, explain:"<strong>Parallel recovery using a non-production test environment</strong> parallel recovery implements DR procedures in a non-production environment, frequently with VMs, leaving production unaffected.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Paper test</b>: A paper test is discussion-only with no execution.</span><span class='qd'><b>Walk-through</b>: A walk-through steps through procedures without restoring data.</span><span class='qd'><b>Tabletop only</b>: A tabletop is limited role-playing, not full parallel execution.</span>" },
  { id:"D4-099", domain:4, obj:"4.2", diff:"hard", q:"The DR test considered the best way to guarantee uninterrupted service, performed on the production environment, is the:", options:["Paper test","Walk-through","Live failover (cutover)","Tabletop simulation"], answer:2, explain:"<strong>Live failover (cutover)</strong> a live failover tests DR on the production environment with the goal of proving zero interruption of service.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Paper test</b>: A paper test only reviews documents and cannot prove live continuity.</span><span class='qd'><b>Walk-through</b>: A walk-through confirms resources but restores no data and is not live.</span><span class='qd'><b>Tabletop simulation</b>: A tabletop is a limited role-play, not a full live cutover.</span>" },
  { id:"D4-100", domain:4, obj:"4.2", diff:"medium", q:"How often, at minimum, should a disaster recovery plan be tested?", options:["Once per decade","Never, if written well","At least annually","Only after a disaster"], answer:2, explain:"<strong>At least annually</strong> DRPs should be tested at least annually with clear, measurable goals and a debriefing process.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Once per decade</b>: Decade-long gaps leave plans dangerously outdated.</span><span class='qd'><b>Never, if written well</b>: An untested plan cannot be trusted regardless of how well written.</span><span class='qd'><b>Only after a disaster</b>: Testing must occur before a disaster to ensure readiness.</span>" }
);
